import scala.util.Random
import java.time.Instant
import java.util.concurrent.ConcurrentHashMap
import scala.jdk.CollectionConverters._

case class Session(
  token: String,
  userId: String,
  createdAt: Instant,
  expiresAt: Instant,
  metadata: Map[String, String] = Map.empty
)

case class ApiKey(
  key: String,
  name: String,
  userId: String,
  createdAt: Instant,
  expiresAt: Option[Instant] = None,
  scopes: Set[String] = Set.empty
)

class TokenGenerationService(
  sessionExpirationSeconds: Long = 3600,
  random: Random = new Random()
) {

  private val sessions = new ConcurrentHashMap[String, Session]().asScala
  private val apiKeys = new ConcurrentHashMap[String, ApiKey]().asScala

  def generateSessionToken(
    userId: String,
    expirationSeconds: Long = sessionExpirationSeconds,
    metadata: Map[String, String] = Map.empty
  ): Session = {
    val token = random.alphanumeric.take(32).mkString
    val now = Instant.now()
    val expiresAt = now.plusSeconds(expirationSeconds)
    
    val session = Session(
      token = token,
      userId = userId,
      createdAt = now,
      expiresAt = expiresAt,
      metadata = metadata
    )
    
    sessions.put(token, session)
    session
  }

  def generateApiKey(
    userId: String,
    name: String,
    expiresAt: Option[Instant] = None,
    scopes: Set[String] = Set.empty
  ): ApiKey = {
    val key = random.alphanumeric.take(32).mkString
    val now = Instant.now()
    
