      key = key,
      name = name,
      userId = userId,
      createdAt = now,
      expiresAt = expiresAt,
      scopes = scopes
    )
    
    apiKeys.put(key, apiKey)
    apiKey
  }

  def validateSession(token: String): Option[Session] = {
    sessions.get(token).filter { session =>
      Instant.now().isBefore(session.expiresAt)
    }
  }

  def validateApiKey(key: String): Option[ApiKey] = {
    apiKeys.get(key).filter { apiKey =>
      apiKey.expiresAt.forall(exp => Instant.now().isBefore(exp))
    }
  }

  def refreshSession(token: String, expirationSeconds: Long = sessionExpirationSeconds): Option[Session] = {
    validateSession(token).map { session =>
      val now = Instant.now()
      val updatedSession = session.copy(expiresAt = now.plusSeconds(expirationSeconds))
      sessions.put(token, updatedSession)
      updatedSession
    }
  }

  def revokeSession(token: String): Boolean = {
    sessions.remove(token).isDefined
  }

  def revokeApiKey(key: String): Boolean = {
    apiKeys.remove(key).isDefined
  }

  def revokeAllUserSessions(userId: String): Int = {
    val userSessions = sessions.filter(_._2.userId == userId).keys.toList
